356: // readCAFile reads the CA cert file from disk.
357: func readCAFile(f string) ([]byte, error) {
358: 	data, err := ioutil.ReadFile(f)
359: 	if err != nil {
360: 		return nil, fmt.Errorf("unable to load specified CA cert %s: %s", f, err)
361: 	}
362: 	return data, nil
363: }
